import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AppContext } from '../App';
import { taxasIRT } from '../data/mockData';
import { ConfiguracaoEmpresa } from '../types';

const Configuracoes: React.FC = () => {
  const { empresa, setEmpresa, isConfigured, setIsConfigured, empresas, setEmpresas, empresaId, setEmpresaId, colaboradores, setColaboradores } = useContext(AppContext);
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('empresa');
  const [config, setConfig] = useState<ConfiguracaoEmpresa>(empresa ? { ...empresa, id: empresa.id || Date.now() } : {
    id: Date.now(),
    nome: '',
    nif: '',
    endereco: '',
    municipio: '',
    provincia: '',
    telefone: '',
    email: '',
    banco: '',
    iban: '',
    taxaINSS: 3,
    taxaINSSPatronal: 8,
    taxaAGT: 2,
    processamentoAutomatico: false,
    envioAutomaticoContracheques: false,
    geracaoAutomaticaGuias: false,
    submissaoAutomaticaMRT: false,
    diaProcessamento: 5,
    regimeFiscal: 'Geral',
    tipoEntidade: 'Lda',
    categoria: 'Empresa'
  });
  const [setupStep, setSetupStep] = useState(!empresa ? 'choice' : 'form');
  const [saved, setSaved] = useState(false);

  const handleChooseCategory = (category: 'Empresa' | 'Particular') => {
    setConfig({ ...config, categoria: category });
    setSetupStep('form');
  };


  const handleSave = () => {
    const empresaComId = { ...config, id: config.id || Date.now() };
    
    // Verificar se a empresa já existe
    const empresaExistente = empresas.findIndex(e => e.id === empresaComId.id);
    
    if (empresaExistente >= 0) {
      // Atualizar empresa existente
      const novasEmpresas = [...empresas];
      novasEmpresas[empresaExistente] = empresaComId;
      setEmpresas(novasEmpresas);
    } else {
      // Adicionar nova empresa
      setEmpresas([...empresas, empresaComId]);
    }
    
    setEmpresa(empresaComId);
    setEmpresaId(empresaComId.id);
    
    // Atualizar colaboradores com o ID da empresa
    const colaboradoresComEmpresa = colaboradores.map(c => ({
      ...c,
      empresaId: empresaComId.id
    }));
    setColaboradores(colaboradoresComEmpresa);
    
    setIsConfigured(true);
    setSaved(true);
    setTimeout(() => {
      setSaved(false);
      if (!isConfigured) {
        navigate('/dashboard');
      }
    }, 1500);
  };

  const tabs = [
    { id: 'empresa', label: 'Dados da Empresa', icon: 'business' },
    { id: 'impostos', label: 'Taxas de Impostos', icon: 'percent' },
    { id: 'processamento', label: 'Processamento', icon: 'sync' },

  ];

  return (
    <div className="p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <nav className="flex items-center gap-2 text-sm text-slate-500 mb-2">
            <span className="hover:text-primary cursor-pointer">Início</span>
            <span className="material-symbols-outlined text-xs">chevron_right</span>
            <span className="text-slate-900 dark:text-white font-medium">Configurações</span>
          </nav>
          <h1 className="text-3xl font-black tracking-tight">Configurações do Sistema</h1>
          <p className="text-slate-500 mt-1">Gerencie os dados da empresa e configurações fiscais.</p>
        </div>
        <button 
          onClick={handleSave}
          className={`px-6 py-2.5 rounded-lg font-bold transition-all flex items-center gap-2 ${
            saved 
              ? 'bg-emerald-500 text-white' 
              : 'bg-primary text-white hover:bg-primary/90 shadow-lg shadow-primary/20'
          }`}
        >
          {saved ? (
            <>
              <span className="material-symbols-outlined">check</span>
              Alterações Salvas
            </>
          ) : (
            <>
              <span className="material-symbols-outlined">save</span>
              Salvar Alterações
            </>
          )}
        </button>
      </div>

      {setupStep === 'choice' ? (
        <div className="max-w-4xl mx-auto mt-12 text-center">
          <h2 className="text-3xl font-black mb-4">Escolha o seu perfil</h2>
          <p className="text-slate-500 mb-10">Como pretende utilizar o SALYA? Seleccione a opção que melhor se adapta a si.</p>
          
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <button 
              onClick={() => handleChooseCategory('Empresa')}
              className="bg-white dark:bg-slate-900 p-8 rounded-2xl border-2 border-slate-100 dark:border-slate-800 hover:border-primary transition-all group text-left shadow-xl"
            >
              <div className="size-16 rounded-2xl bg-primary/10 flex items-center justify-center text-primary mb-6 group-hover:scale-110 transition-transform">
                <span className="material-symbols-outlined text-4xl">business</span>
              </div>
              <h3 className="text-xl font-bold mb-2">Empresa ou Negócio</h3>
              <p className="text-slate-500 text-sm">Para empresas, multinacionais ou pequenos negócios com diversos funcionários e obrigações fiscais complexas.</p>
            </button>

            <button 
              onClick={() => handleChooseCategory('Particular')}
              className="bg-white dark:bg-slate-900 p-8 rounded-2xl border-2 border-slate-100 dark:border-slate-800 hover:border-primary transition-all group text-left shadow-xl"
            >
              <div className="size-16 rounded-2xl bg-indigo-500/10 flex items-center justify-center text-indigo-500 mb-6 group-hover:scale-110 transition-transform">
                <span className="material-symbols-outlined text-4xl">home</span>
              </div>
              <h3 className="text-xl font-bold mb-2">Particular / Doméstico</h3>
              <p className="text-slate-500 text-sm">Para gerir o salário de um motorista, empregado doméstico ou trabalhador em sua residência particular.</p>
            </button>
          </div>
        </div>
      ) : (
        <div className="flex gap-8">
          <aside className="w-64 shrink-0">
            <nav className="space-y-1">
              {tabs.map(tab => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
                    activeTab === tab.id
                      ? 'bg-primary/10 text-primary font-medium'
                      : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
                  }`}
                >
                  <span className="material-symbols-outlined">{tab.icon}</span>
                  {tab.label}
                </button>
              ))}
            </nav>
          </aside>


        <div className="flex-1">
          {activeTab === 'empresa' && (
            <div className="space-y-6">
              <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
                <h3 className="font-bold text-lg mb-4">Identidade da Empresa</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-500 dark:text-slate-400 mb-2">
                      {config.categoria === 'Particular' ? 'Nome do Empregador' : 'Nome da Empresa'}
                    </label>
                    <input 
                      type="text" 
                      value={config.nome}
                      placeholder={config.categoria === 'Particular' ? 'Ex: José da Silva' : 'Ex: SALYA Lda'}
                      onChange={(e) => setConfig({...config, nome: e.target.value})}
                      className="w-full px-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800"
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-slate-500 dark:text-slate-400 mb-2">NIF</label>
                    <input 
                      type="text" 
                      value={config.nif}
                      onChange={(e) => setConfig({...config, nif: e.target.value})}
                      className="w-full px-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-500 dark:text-slate-400 mb-2">Regime Fiscal</label>
                    <select 
                      value={config.regimeFiscal}
                      onChange={(e) => setConfig({...config, regimeFiscal: e.target.value})}
                      className="w-full px-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800"
                    >
                      <option>Geral</option>
                      <option>Simplificado</option>
                      <option>Isento</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-500 dark:text-slate-400 mb-2">Tipo de Entidade</label>
                    <select 
                      value={config.tipoEntidade}
                      onChange={(e) => setConfig({...config, tipoEntidade: e.target.value})}
                      className="w-full px-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800"
                    >
                      <option>Lda</option>
                      <option>SA</option>
                      <option>EI</option>
                      <option> Sucursal</option>
                    </select>
                  </div>
                </div>
              </div>

              <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
                <h3 className="font-bold text-lg mb-4">Endereço</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="md:col-span-2">
                    <label className="block text-sm font-medium text-slate-500 dark:text-slate-400 mb-2">Endereço</label>
                    <input 
                      type="text" 
                      value={config.endereco}
                      onChange={(e) => setConfig({...config, endereco: e.target.value})}
                      className="w-full px-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-500 dark:text-slate-400 mb-2">Município</label>
                    <input 
                      type="text" 
                      value={config.municipio}
                      onChange={(e) => setConfig({...config, municipio: e.target.value})}
                      className="w-full px-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-500 dark:text-slate-400 mb-2">Província</label>
                    <input 
                      type="text" 
                      value={config.provincia}
                      onChange={(e) => setConfig({...config, provincia: e.target.value})}
                      className="w-full px-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800"
                    />
                  </div>
                </div>
              </div>

              <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
                <h3 className="font-bold text-lg mb-4">Dados Bancários</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-500 dark:text-slate-400 mb-2">Banco</label>
                    <select 
                      value={config.banco}
                      onChange={(e) => setConfig({...config, banco: e.target.value})}
                      className="w-full px-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800"
                    >
                      <option>Banco Angolano de Investimento (BAI)</option>
                      <option>Banco de Fomento Angola (BFA)</option>
                      <option>Banco de Poupança e Crédito (BPC)</option>
                      <option>Banco Millennium Atlântico (BMA)</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-500 dark:text-slate-400 mb-2">IBAN</label>
                    <input 
                      type="text" 
                      value={config.iban}
                      onChange={(e) => setConfig({...config, iban: e.target.value})}
                      className="w-full px-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 font-mono"
                    />
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'impostos' && (
            <div className="space-y-6">
              <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
                <h3 className="font-bold text-lg mb-4">Taxas de INSS (2026)</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-500 dark:text-slate-400 mb-2">Taxa Trabalhador (%)</label>
                    <input 
                      type="number" 
                      value={config.taxaINSS}
                      onChange={(e) => setConfig({...config, taxaINSS: Number(e.target.value)})}
                      className="w-full px-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-500 dark:text-slate-400 mb-2">Taxa Patronal (%)</label>
                    <input 
                      type="number" 
                      value={config.taxaINSSPatronal}
                      onChange={(e) => setConfig({...config, taxaINSSPatronal: Number(e.target.value)})}
                      className="w-full px-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800"
                    />
                  </div>
                </div>
              </div>

              <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
                <h3 className="font-bold text-lg mb-4">Tabela de IRT - Escalões 2026</h3>
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead className="bg-slate-50 dark:bg-slate-800">
                      <tr>
                        <th className="p-3 text-xs font-bold text-slate-500 uppercase">Escalão</th>
                        <th className="p-3 text-xs font-bold text-slate-500 uppercase">Mínimo (Kz)</th>
                        <th className="p-3 text-xs font-bold text-slate-500 uppercase">Máximo (Kz)</th>
                        <th className="p-3 text-xs font-bold text-slate-500 uppercase">Taxa (%)</th>
                        <th className="p-3 text-xs font-bold text-slate-500 uppercase">Parcela a Abater</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                      {taxasIRT.map(taxa => (
                        <tr key={taxa.id} className="hover:bg-slate-50 dark:hover:bg-slate-800">
                          <td className="p-3 font-medium">{taxa.faixa}</td>
                          <td className="p-3">{taxa.minimo.toLocaleString()}</td>
                          <td className="p-3">{taxa.maximo.toLocaleString()}</td>
                          <td className="p-3">{taxa.taxa}%</td>
                          <td className="p-3">{taxa.parcelaAbt.toLocaleString()} Kz</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'processamento' && (
            <div className="space-y-6">
              <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
                <h3 className="font-bold text-lg mb-4">Configurações de Processamento</h3>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-slate-500 dark:text-slate-400 mb-2">Dia de Processamento</label>
                    <input 
                      type="number" 
                      min={1}
                      max={28}
                      value={config.diaProcessamento}
                      onChange={(e) => setConfig({...config, diaProcessamento: Number(e.target.value)})}
                      className="w-full px-4 py-2.5 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800"
                    />
                  </div>
                  <div className="flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800 rounded-lg">
                    <div>
                      <p className="font-medium">Processamento Automático</p>
                      <p className="text-sm text-slate-500">Executar processamento salarial automaticamente</p>
                    </div>
                    <button 
                      onClick={() => setConfig({...config, processamentoAutomatico: !config.processamentoAutomatico})}
                      className={`w-12 h-6 rounded-full transition-colors ${config.processamentoAutomatico ? 'bg-primary' : 'bg-slate-300'}`}
                    >
                      <div className={`w-5 h-5 bg-white rounded-full shadow transform transition-transform ${config.processamentoAutomatico ? 'translate-x-6' : 'translate-x-0.5'}`} />
                    </button>
                  </div>
                  <div className="flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800 rounded-lg">
                    <div>
                      <p className="font-medium">Envio Automático de Contracheques</p>
                      <p className="text-sm text-slate-500">Enviar contracheques por email automaticamente</p>
                    </div>
                    <button 
                      onClick={() => setConfig({...config, envioAutomaticoContracheques: !config.envioAutomaticoContracheques})}
                      className={`w-12 h-6 rounded-full transition-colors ${config.envioAutomaticoContracheques ? 'bg-primary' : 'bg-slate-300'}`}
                    >
                      <div className={`w-5 h-5 bg-white rounded-full shadow transform transition-transform ${config.envioAutomaticoContracheques ? 'translate-x-6' : 'translate-x-0.5'}`} />
                    </button>
                  </div>
                </div>
              </div>
            </div>
          )}


          </div>
        </div>
      )}
    </div>


  );
};

export default Configuracoes;
